const { define, queries, query } = initServe({
  context: () => ({ db }),
});

export const api = define({
  queries: queries({
    sessionsQuery: query
      .describe('Example query using the sessions table')
      .query(async ({ ctx }) =>
        ctx.db
          .table('sessions')
          .select('*')
          .limit(10)
